// middleware.ts
import { auth } from '@/lib/auth';

export default auth((req) => {
    if (!req.auth && req.nextUrl.pathname.startsWith('/dashboard')) {
        return Response.redirect(new URL('/login', req.url));
    }
});

export const config = {
    matcher: ['/dashboard/:path*', '/api/:path*']
};
